 1	import type { FC } from 'react';
 2	
 3	import SectionHeading from '@components/headers/SectionHeading';
 4	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 5	import { isEmpty } from '@utils/helpers';
 6	import { useForkliftTranslation } from '@utils/i18n';
 7	
 8	import type { DetailsSectionProps } from './utils/types';
 9	import { getDetailsSectionByType } from './utils/utils';
10	
11	const DetailsSection: FC<DetailsSectionProps> = ({ data }) => {
12	  const { t } = useForkliftTranslation();
13	
14	  const { permissions, provider } = data;
15	
16	  if (isEmpty(provider) || isEmpty(permissions))
17	    return <span className="text-muted">{t('No provider data available.')}</span>;
18	
19	  const DetailsSectionByType = getDetailsSectionByType(provider?.spec?.type);
20	  if (!DetailsSectionByType) return null;
21	
22	  return (
23	    <PageSection variant={PageSectionVariants.light} className="forklift-page-section--details">
24	      <SectionHeading text={t('Provider details')} />
25	      <DetailsSectionByType data={data} />
26	    </PageSection>
27	  );
28	};
29	
30	export default DetailsSection;

